mapper.select:
select id, user_id as userId, action_type as actionType, ref_type as refType, ref_id as refId,
       detail, create_time as createTime
from room_business_audit

    and action_type = #{actionType}
    and user_id = #{userId}
    and create_time >= #{beginTime}
    and create_time <= #{endTime}

order by id desc
limit 500
